import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

export default function LoginPage() {
  const [phone, setPhone] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    const auth = JSON.parse(localStorage.getItem('pizzaAuth') || '{}');
    if (auth.verified) navigate('/');
  }, []);

  const handleSubmit = e => {
    e.preventDefault();
    if (!phone.trim()) return;
    localStorage.setItem('pizzaAuth', JSON.stringify({ phone: phone.trim(), verified: false }));
    navigate('/verify');
  };

  return (
    <div className="max-w-sm mx-auto mt-16 p-8 bg-white rounded-2xl shadow-xl text-center">
      <div className="text-5xl mb-3">🍕</div>
      <h1 className="text-3xl font-bold text-tomato mb-1">פיצה סטורי</h1>
      <p className="text-gray-500 text-sm mb-8">הכנס מספר טלפון כדי להמשיך</p>

      <form onSubmit={handleSubmit}>
        <div className="mb-5">
          <input
            type="tel"
            value={phone}
            onChange={e => setPhone(e.target.value)}
            required
            placeholder="050-0000000"
            className="w-full border-2 rounded-xl px-4 py-3 text-center text-xl focus:border-tomato focus:outline-none transition"
            dir="ltr"
            autoFocus
          />
        </div>
        <button
          type="submit"
          className="w-full bg-tomato text-white py-3 rounded-xl font-bold text-lg hover:bg-red-700 transition"
        >
          שלח קוד אימות 📲
        </button>
      </form>

      <button
        onClick={() => navigate('/')}
        className="mt-3 w-full border border-gray-200 text-gray-500 py-2.5 rounded-xl hover:bg-gray-50 transition text-sm"
      >
        ← חזרה לתפריט
      </button>
    </div>
  );
}
